INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Serverless, browser-based editing$q$, $q$All tree building and editing happens locally in the browser, so no personal genealogy data is transmitted to or stored on Genea.app servers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$GEDCOM import and export$q$, $q$Fully compatible with the GEDCOM standard, allowing trees to be imported from and exported to Ancestry, MyHeritage, FamilySearch, and other genealogy tools.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Git-based sync and version history$q$, $q$Connects to GitHub, GitLab, Gitea, Gogs, or GitBucket so users can commit tree changes and keep a full version history of their research.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$No account required$q$, $q$Users can start building a tree immediately without signing up, entering an email address, or creating a password.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Sample trees for exploration$q$, $q$Preloaded example trees, including royal lineages, US presidents, and a Harry Potter family tree, let new users learn the interface risk-free.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Cross-device compatibility$q$, $q$Works in modern browsers on both desktop and mobile devices for viewing and light editing on the go.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Open-source codebase$q$, $q$Released under the MIT License on GitHub, allowing developers to inspect, self-host, fork, or extend the application.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$No vendor lock-in$q$, $q$Because data is stored as a standard GEDCOM file that the user controls, switching to another genealogy tool later requires no migration process.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Completely free with no paid tiers or hidden costs$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Strong privacy model since no genealogy data is sent to a remote server$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Open-source and self-inspectable, appealing to technical and privacy-conscious users$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Git integration gives version-controlled history of family tree research$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$No account or sign-up friction to start building a tree$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Lacks the record-hint databases, historical archives, and DNA matching found in paid genealogy platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$No built-in collaborative research community or shared family tree hosting$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Git-based syncing has a learning curve for non-technical users$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$As a small volunteer-maintained project, there is no dedicated customer support or guaranteed roadmap$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Editing large, complex trees is more comfortable on desktop than mobile$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Is Genea.app really free?$q$, $q$Yes. Genea.app is free and open source with no subscription plans, paid tiers, or account requirements.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Does Genea.app store my family tree data on its servers?$q$, $q$No. All processing happens in the browser, so Genea.app does not host or store user genealogy data; users choose where their GEDCOM file is saved.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Can I import a tree from Ancestry or MyHeritage?$q$, $q$Yes. Genea.app supports the standard GEDCOM format, which is exportable from Ancestry, MyHeritage, FamilySearch, and most other genealogy services.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$How do I sync my tree across multiple devices?$q$, $q$You can manually export and move the GEDCOM file yourself, or use Genea.app's built-in Git integration to sync changes through GitHub, GitLab, or a self-hosted Git server.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Is Genea.app open source?$q$, $q$Yes, it is released under the MIT License and maintained publicly on GitHub under the genea-app organization.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Does Genea.app offer DNA matching or historical record search?$q$, $q$No, Genea.app is focused purely on building and editing GEDCOM family trees; it does not include DNA matching or record-hint research features found on commercial platforms.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Privacy-conscious family tree editing$q$, $q$Users who don't want their family history data hosted on a third-party server can build and edit trees entirely offline in the browser.$q$, $q$Privacy-focused genealogy hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Portable GEDCOM editing between services$q$, $q$Import a GEDCOM file exported from a commercial platform, make edits or corrections, then re-export it without being locked into one vendor.$q$, $q$Genealogists using multiple genealogy tools$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Version-controlled family research$q$, $q$Technical users can track the evolution of their family tree over time using Git commits, branches, and history.$q$, $q$Developers and technical genealogy researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$Free / Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited family tree creation and editing","GEDCOM import and export","Git-based sync (GitHub, GitLab, Gitea, Gogs, GitBucket)","Sample trees included","No account required","Open-source, self-hostable codebase"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Genea.app is a free, open-source, browser-based application for creating and editing family trees using the GEDCOM standard. It runs entirely client-side, with no account, no server, and no backend database, which the project frames as a privacy-first alternative to hosted genealogy platforms.$q$, $q$The tool is maintained on GitHub under the MIT License by the genea-app organization. It is designed for people who already have, or want to create, a standard GEDCOM file and prefer to keep full control of where that data is stored rather than uploading it to a commercial genealogy service.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users can start a tree from scratch or import an existing GEDCOM file exported from services like MyHeritage, FamilySearch, or Ancestry, then edit and re-export it at any time, avoiding vendor lock-in.$q$, $q$For multi-device use, Genea.app offers manual file export/import as well as a built-in Git integration that syncs tree changes to GitHub, GitLab, or self-hosted Git servers such as Gitea, Gogs, or GitBucket, giving users full version history of their research.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Genea.app is completely free and open source; there are no paid tiers, subscriptions, or account requirements of any kind.$q$, $q$Because the project has no hosting costs tied to user data (all processing happens in the browser), there is no usage-based billing model either, making it effectively free for unlimited personal use.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('cd31d369-2e60-4849-9a2b-8481c41a9d08', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Family tree building$q$, $q$Record individuals, partnerships, couples (including same-sex couples), and children to construct multi-generational family trees.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Team-based collaboration$q$, $q$Create separate teams for each family tree and invite collaborators to research and edit together.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$GEDCOM import and export$q$, $q$Actively developed support for the GEDCOM standard, allowing data exchange with other genealogy platforms.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Public demo trees$q$, $q$Built-in demonstration trees for the British Royal Family and the Kennedy family let new users explore the tool without entering personal data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Multi-language support$q$, $q$The interface supports at least eleven languages, including English, French, Spanish, German, and Mandarin.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Open-source, self-hostable codebase$q$, $q$Released under the MIT License and built on Laravel, allowing developers to inspect, modify, or self-host the application.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Account-based access$q$, $q$User registration and login system to keep personal family tree data private to the owning team.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Completely free for non-commercial use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Open source under a permissive MIT License$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Team-based collaboration model for shared family research$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Inclusive support for same-sex couples in family structures$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Broad multi-language support for an international audience$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$No public historical record archive or DNA matching, unlike commercial genealogy platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$GEDCOM import/export functionality is still being actively developed and expanded$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$No published company history, funding, or long-term roadmap since it is a small studio project$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Smaller user community than established players like Ancestry or MyHeritage$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Founding year and company scale are not publicly documented$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Is Genealogy free to use?$q$, $q$Yes, it is free to use for non-commercial purposes.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Who built Genealogy?$q$, $q$It is developed and maintained by KREAWEB, a web development studio, with GitHub user MGeurts credited as the primary developer.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$What technology is Genealogy built on?$q$, $q$It is a PHP web application built with the Laravel framework, with the codebase publicly available and updated alongside newer Laravel releases.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Can I import my existing family tree?$q$, $q$GEDCOM import and export functionality is available and under active development, allowing data exchange with other genealogy tools.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Does Genealogy support same-sex couples in family trees?$q$, $q$Yes, the platform explicitly supports recording partners and couples, including same-sex couples.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Is the source code available?$q$, $q$Yes, Genealogy is released under the MIT License and its source is publicly available on GitHub.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Collaborative family history research$q$, $q$A group of relatives creates a shared team to jointly build and maintain a single family tree.$q$, $q$Families and genealogy hobbyist groups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Learning genealogy software via public demos$q$, $q$New users explore the British Royal Family or Kennedy family demo trees to learn the interface before creating their own.$q$, $q$First-time genealogy researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Self-hosted family archive$q$, $q$Technically inclined users deploy their own instance of the open-source Laravel application to keep full control of their family history data.$q$, $q$Developers and privacy-focused hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$Free / Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited family tree creation for non-commercial use","Team-based collaboration","GEDCOM import/export (actively expanding)","Multi-language interface","Self-hostable, open-source codebase"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Genealogy is a free, open-source family tree application built on the Laravel PHP framework and maintained by web studio KREAWEB (GitHub user MGeurts). It focuses on recording individuals, partnerships, and children to build browsable, multi-generational family trees.$q$, $q$The project is distributed under the MIT License, is explicitly free for non-commercial use, and supports at least eleven languages, reflecting an international, community-oriented approach rather than a commercial SaaS model.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes recording persons, partners and couples (including same-sex couples), and children, plus team-based ownership so multiple collaborators can work on a shared family tree.$q$, $q$The platform ships with two public demo trees, the British Royal Family and the Kennedy family, and includes GEDCOM import/export functionality that is actively being expanded for broader interoperability with other genealogy tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Genealogy is free to use for non-commercial purposes, with no paid subscription tiers currently documented.$q$, $q$Because it is open source under the MIT License, technically inclined users can also self-host their own instance of the application at no licensing cost.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9a671332-0a6d-44a2-a483-911ca563acab', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Locadex AI internationalization agent$q$, $q$Connects to a codebase, automatically detects and internationalizes hard-coded UI text, and opens pull requests triggered by commits or PRs.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Multi-framework developer SDKs$q$, $q$Native SDKs for React, Next.js, React Native, Node.js, and Python handle translated text, pluralization, currency, dates, and locale routing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Translation Editor$q$, $q$A review workspace where teams can see source and translated text side by side, track diffs, and approve or edit AI-generated translations.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Global Translation CDN$q$, $q$A globally distributed delivery layer that pushes over-the-air translation updates to production apps without a full redeploy.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$100+ language support$q$, $q$Supports translation into more than 100 languages and locales with automatic language detection.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Live user-generated content translation$q$, $q$Translates dynamic, user-generated content in real time, not just static UI strings.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Glossaries and locale rules$q$, $q$Custom context controls let teams enforce consistent terminology, such as keeping brand names untranslated, across all languages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Enterprise compliance$q$, $q$SOC 2 Type II, GDPR, and ISO 27001 compliance support security-conscious enterprise adoption.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Free Starter tier with unlimited users, projects, and languages$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Automates internationalization work, not just translation, via the Locadex AI agent$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Deep framework-native support for React and Next.js, including SEO-friendly locale routing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Billed only on input length, not translated output length$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Enterprise-grade compliance certifications (SOC 2 Type II, GDPR, ISO 27001)$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Enterprise pricing is fully custom and not published, requiring a sales conversation$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$AI-driven translation still benefits from human review for nuanced or brand-sensitive content$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Best suited to React/Next.js-centric stacks; other frameworks have less native tooling$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$As a relatively young company founded in 2023, long-term track record and stability are still being established$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Exact funding figures are not officially disclosed, only reported by third-party startup trackers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Is General Translation free to use?$q$, $q$Yes, the Starter plan is free ($0) and includes unlimited users, projects, and languages, with usage-based charges applying only once included workflow limits are exceeded.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$What frameworks does General Translation support?$q$, $q$It offers dedicated SDKs for React, Next.js, React Native, Node.js, and Python.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$What is Locadex?$q$, $q$Locadex is General Translation's AI agent that connects to a codebase, automatically internationalizes hard-coded UI text, and opens pull requests with the changes and translations.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$How many languages does General Translation support?$q$, $q$The platform supports translation into more than 100 languages and locales.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Is General Translation suitable for enterprises?$q$, $q$Yes. It offers a custom Enterprise plan with custom integrations, an SLA, forward-deployed engineers, and supports SOC 2 Type II, GDPR, and ISO 27001 compliance.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Who founded General Translation?$q$, $q$General Translation was founded in 2023 by CEO Archie McKenzie and is headquartered in San Francisco, California.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Automated codebase internationalization$q$, $q$Engineering teams use the Locadex AI agent to find and wrap untranslated strings automatically instead of manually preparing a codebase for localization.$q$, $q$Startup and mid-size engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Continuous translation delivery$q$, $q$Product teams push translation updates to a live application through the Translation CDN without redeploying the app.$q$, $q$Product and localization teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Enterprise localization with compliance requirements$q$, $q$Larger organizations needing SOC 2, GDPR, and ISO 27001 compliant localization infrastructure adopt the custom Enterprise plan.$q$, $q$Enterprise software companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Starter$q$, $q$$0$q$, $q$Free, with usage-based overage$q$, NULL, $q$["Unlimited users, projects, and languages","Translation Editor","GitHub integration","Locadex AI agent","Per-workflow usage pricing beyond included limits"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$Enterprise$q$, $q$Contact for pricing$q$, $q$Custom$q$, NULL, $q$["All Starter features","Custom integrations","Custom SLA","Forward-deployed engineers","Custom workflows and pricing"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$General Translation, founded in 2023 by CEO Archie McKenzie and headquartered in San Francisco, is a developer-first localization platform combining an AI internationalization agent, framework-native SDKs, a human translation review editor, and a global translation content delivery network.$q$, $q$The company positions itself around automating not just translation but the underlying internationalization work of a codebase, using its 'Locadex' AI agent to find and wrap untranslated strings and open pull requests automatically.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform supports React, Next.js, React Native, Node.js, and Python through dedicated SDKs, and covers over 100 languages and locales with automatic language detection and locale-aware routing.$q$, $q$A Translation Editor lets human reviewers approve or refine AI-generated translations side by side with source text, while the Translation CDN delivers over-the-air translation updates to live apps without a full redeploy.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ac787a71-4482-4430-83bd-72c102061928', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$General Translation uses a freemium model. The Starter plan is $0 and includes unlimited users, projects, and languages, with usage-based charges applying per-workflow once included limits are exceeded, billed only on input length rather than translated output length.$q$, $q$The Enterprise plan is custom-priced and adds custom integrations, a dedicated SLA, and forward-deployed engineering support for larger organizations with complex localization and compliance needs.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ac787a71-4482-4430-83bd-72c102061928', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ac787a71-4482-4430-83bd-72c102061928', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ac787a71-4482-4430-83bd-72c102061928', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ac787a71-4482-4430-83bd-72c102061928', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ac787a71-4482-4430-83bd-72c102061928', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Multi-format chat rooms$q$, $q$Full-featured text chat with @mentions, threaded replies, reactions, GIFs, attachments, polls, pins, and typing indicators.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Audio rooms$q$, $q$Live voice hangout spaces for group conversation, similar to voice channels or drop-in audio spaces.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Broadcast/livestream rooms$q$, $q$Stream events, tutorials, or gatherings live with up to nine people on-air and thousands of viewers watching.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Video rooms$q$, $q$Group video calls supporting up to sixteen simultaneous participants.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Forum rooms$q$, $q$Threaded, longer-form discussion spaces better suited to in-depth topics than a fast-moving chat feed.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Event planning and calendar$q$, $q$Built-in event invitations and a centralized shared calendar to organize both online and offline meetups.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Member screening and roles$q$, $q$Custom questionnaires to screen prospective members plus configurable roles and permissions for community management.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Token-gating$q$, $q$Restrict community access based on ownership of a specific blockchain token or NFT.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Completely free across iOS, Android, and web$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Combines chat, audio, video, forum, and livestreaming in one unified product$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Strong focus on turning online communities into real-world, local meetups$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Backed by significant funding and now the resources of Bumble Inc. post-acquisition$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Inclusive, community-first positioning with LGBTQIA+ focused features$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$No enterprise-grade workplace features (e.g., admin controls, SSO) compared to tools like Slack$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Smaller mainstream user base than Discord for hobbyist and gaming communities$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Future product direction is less certain following the 2024 acquisition by Bumble Inc.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$No disclosed premium tier or advanced monetization tools for community organizers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Detailed current company size and internal metrics are not publicly disclosed$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Is Geneva free to use?$q$, $q$Yes, Geneva is free to use on iPhone, Android, and the web.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Who founded Geneva?$q$, $q$Geneva was founded in 2018 by Justin Hauser, who is also a co-founder of the CBD beverage company Recess.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Is Geneva still an independent company?$q$, $q$No, Geneva was acquired by Bumble Inc. in a deal that closed on July 1, 2024, and now operates as a Bumble-owned brand.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$How is Geneva different from Discord or Slack?$q$, $q$Geneva focuses on helping local, real-world communities and clubs coordinate both online conversation and in-person events, combining chat, audio, video, forums, and livestreaming in one app, whereas Discord skews toward gaming communities and Slack targets workplace teams.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$How many people can join a Geneva video call?$q$, $q$Geneva video rooms support up to sixteen simultaneous participants.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Does Geneva support token-gated communities?$q$, $q$Yes, Geneva includes token-gating, which restricts community access based on ownership of a specific blockchain token or NFT.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Local hobby and interest clubs$q$, $q$Book clubs, running groups, and other interest-based communities use Geneva to chat online and plan in-person meetups.$q$, $q$Community organizers and hobby groups$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Livestreamed community events$q$, $q$Groups broadcast events, tutorials, or gatherings to members via Geneva's broadcast rooms with on-air hosts and a large viewing audience.$q$, $q$Event hosts and content creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Brand community engagement$q$, $q$Consumer brands use Geneva for private group messaging with fans and customers alongside other tools like Slack.$q$, $q$Consumer brands and marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Chat, audio, video, forum, and broadcast rooms","Event planning and shared calendar","Member screening questionnaires","Roles and permissions","Token-gating for blockchain communities","Available on iOS, Android, and web"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Geneva is a free, all-in-one group communication app founded in 2018 by Justin Hauser (also a co-founder of Recess) and headquartered in New York City. It targets clubs, hobby groups, and local communities rather than enterprise teams, combining chat, audio, video, forums, and livestreaming in a single product.$q$, $q$Geneva raised roughly $26.5 million in funding across three rounds before being acquired by Bumble Inc. in a deal that closed on July 1, 2024, and continues to operate as its own brand under Bumble's ownership.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Groups can combine chat rooms, audio rooms, forum rooms, broadcast rooms (livestreaming to up to nine on-air participants and thousands of viewers), and video rooms (up to sixteen participants) within a single community space.$q$, $q$Community management tools include member screening questionnaires, built-in event planning and calendars, customizable roles and permissions, and token-gating for blockchain-based communities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Geneva is free to use on iPhone, Android, and the web, with no publicly disclosed paid subscription tier for community members.$q$, $q$Monetization details post-acquisition by Bumble Inc. are not publicly broken out separately from Bumble's broader corporate financials.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f060f9b6-0029-44ee-a1ce-f641464783dd', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Web-server-based architecture$q$, $q$Runs as a lightweight embedded web server that hosts and dynamically serves any number of genealogical databases via a standard browser.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Relationship and consanguinity calculator$q$, $q$Efficiently computes how closely related two individuals are and calculates inbreeding coefficients within a database.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Automatic statistics generation$q$, $q$Produces lists of oldest living individuals, recent weddings or deaths, and age pyramids for a given year.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$GEDCOM and native GW format support$q$, $q$Imports and exports data in both the industry-standard GEDCOM format and GeneWeb's own native GW format.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Wikitext notes with cross-references$q$, $q$Attach richly formatted notes to individuals and families, including internal links and embedded media.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$gwsetup administration tool$q$, $q$A browser-based configuration and maintenance interface that removes the need for command-line administration.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Multi-language interface$q$, $q$Localized into at least nine languages, including French, English, German, Dutch, and Spanish.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Cross-platform support$q$, $q$Runs on Unix, Linux, Microsoft Windows, and macOS.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Completely free and open source under GPL-2.0$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Proven at massive scale, powering databases like Roglo with millions of individuals$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Advanced relationship/consanguinity calculation not commonly found in consumer genealogy tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Long track record of continuous development since 1998$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Flexible deployment as a private offline tool or a public-facing web genealogy database$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Requires self-hosting and some technical setup, unlike consumer SaaS genealogy platforms$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Web interface design is dated compared to modern commercial genealogy services$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$No official customer support; relies on community and documentation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$No built-in historical record archive or DNA matching like Ancestry or MyHeritage$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$OCaml-based codebase can be less approachable for contributors unfamiliar with the language$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Is GeneWeb free?$q$, $q$Yes, GeneWeb is free and open source under the GNU General Public License version 2.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Who created GeneWeb?$q$, $q$GeneWeb was created in 1998 by Daniel de Rauglaudre, a researcher at Inria, and written in OCaml.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$What is Roglo?$q$, $q$Roglo is a large public genealogy database, containing more than 8.5 million individuals, built on the GeneWeb engine.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Does GeneWeb support GEDCOM?$q$, $q$Yes, GeneWeb can import and export genealogical data in both the GEDCOM standard and its own native GW format.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$What platforms does GeneWeb run on?$q$, $q$GeneWeb runs on Unix, Linux, Microsoft Windows, and macOS.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Do I need to self-host GeneWeb?$q$, $q$Yes, GeneWeb is self-hosted software; users run it locally for private research or deploy it to a server to make a database accessible online.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Large-scale public genealogy databases$q$, $q$Researchers and organizations build multi-million-person public genealogy databases similar to Roglo using GeneWeb's server architecture.$q$, $q$Genealogical societies and large research projects$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Private offline family research$q$, $q$Individuals run GeneWeb locally to build and analyze a private family tree with relationship and consanguinity calculations.$q$, $q$Individual genealogy researchers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Self-hosted family history websites$q$, $q$Technical users deploy GeneWeb on a personal server to make a family tree browsable to relatives online.$q$, $q$Technical genealogy hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$Free / Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted web server for unlimited databases","GEDCOM and GW format import/export","Relationship and consanguinity calculator","Automatic statistics and age pyramids","gwsetup administration interface","Multi-language support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GeneWeb is a free, open-source genealogy software engine written in OCaml, created in 1998 by Inria researcher Daniel de Rauglaudre. It operates as a lightweight web server capable of hosting any number of genealogical databases and dynamically generating browsable HTML pages.$q$, $q$Released under the GPL-2.0 license and maintained on GitHub, GeneWeb has powered some of the largest public genealogical databases in the world, most notably Roglo, which contains more than 8.5 million individuals.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$GeneWeb includes an efficient relationship and consanguinity rate calculator, automatic statistics such as oldest-living-person lists and age pyramids, and wikitext-formatted notes with internal cross-references and embedded media.$q$, $q$It supports both a native GW database format and the industry-standard GEDCOM format for import/export, and includes a browser-based admin utility (gwsetup) for configuring and maintaining installations without command-line expertise.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GeneWeb is entirely free and open source under the GPL-2.0 license, with no paid tiers, subscriptions, or licensing fees.$q$, $q$Users self-host the software on their own hardware or server, so the only ongoing cost is whatever infrastructure the operator chooses to run it on.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
