INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('eed15499-677d-4aec-b709-b24744a436e5', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Large-scale SERP data API$q$, $q$Retrieves real-time paid and organic search results from over 50,000 locations across Google, Bing, Baidu, YouTube, Yahoo, and Naver.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Local citation finder$q$, $q$Identifies and audits business listings across directories relevant to local search ranking factors.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Geographic rank tracking$q$, $q$Tracks keyword rankings by precise location, useful for multi-location businesses and franchises.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Keyword research and density analysis$q$, $q$Discovers relevant keywords and analyzes keyword density for on-page optimization.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Competitive intelligence$q$, $q$Analyzes competitors' organic rankings and advertising presence, including advertiser competition analysis.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Voice search data extraction$q$, $q$Tracks how content performs in voice-assistant search results.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$White-label reporting and API access$q$, $q$Agencies can generate white-labeled client reports and integrate raw ranking data via API and Google Sheets integration.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Automated reporting$q$, $q$Scheduled, automated reports keep stakeholders updated on ranking performance without manual pulls.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Highly granular, location-precise rank tracking across 50,000+ locations$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Raw SERP API access appeals to agencies and SaaS companies building their own tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Multiple search engines covered beyond just Google, including Bing, Baidu, YouTube, Yahoo, and Naver$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$No-contract, pay-as-you-go billing with cancel-anytime flexibility$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Long operating history since 2011 with a large existing customer base$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Credit-based pricing can be complex to estimate, especially when tracking both desktop and mobile$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Credits do not roll over between billing periods, so unused capacity is lost$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Entry pricing at $99/month is higher than some general-purpose rank trackers' base tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Smaller brand recognition compared to category leaders like SEMrush or Ahrefs$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Company size and team are lean, which may limit support responsiveness at scale$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$How does GeoRanker pricing work?$q$, $q$GeoRanker uses a monthly credit system where usage is calculated based on the number of keywords, locations, device types, and search engines tracked; plans range from $99/month to $490/month.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$What search engines does GeoRanker track?$q$, $q$GeoRanker tracks rankings across Google, Bing, Baidu, YouTube, Yahoo, and Naver, on both desktop and mobile.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Is GeoRanker good for franchises and multi-location businesses?$q$, $q$Yes, its core strength is precise, location-by-location rank tracking, which is especially useful for businesses that need visibility in specific cities or neighborhoods.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Does GeoRanker offer an API?$q$, $q$Yes, GeoRanker's core product is a large-scale SERP data API that other agencies and software companies can integrate into their own tools.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$When was GeoRanker founded?$q$, $q$GeoRanker was founded in 2011, originally based in Bucharest, Romania, with its headquarters more recently reported in Luxembourg.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Does GeoRanker require a long-term contract?$q$, $q$No, GeoRanker is offered on a pay-as-you-go basis with no contracts and the ability to cancel at any time.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$Multi-location and franchise rank tracking$q$, $q$Businesses with many physical locations track how they rank for relevant keywords in each specific city or neighborhood.$q$, $q$Franchises and multi-location businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$SEO agency client reporting$q$, $q$Agencies use white-label reports, automated reporting, and API access to manage ranking data across many client accounts.$q$, $q$SEO agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$SaaS integration of local search data$q$, $q$Software companies integrate GeoRanker's SERP API directly into their own products to power location-based search features.$q$, $q$SaaS and martech companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$PRO$q$, $q$$99$q$, $q$per month$q$, NULL, $q$["10,000 monthly credits","50 projects","100 tracked keywords","Mobile rank tracking","Custom location tracking","Keyword discovery and competition analysis","API access, white-label reports, Sheets integration","Automated reports and live support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$AGENCIES$q$, $q$$249$q$, $q$per month$q$, NULL, $q$["50,000 monthly credits","100 projects","500 tracked keywords","All PRO features","Advertiser competition analysis","Website ranking tool","3 training sessions"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$ENTERPRISES$q$, $q$$490$q$, $q$per month$q$, NULL, $q$["120,000 monthly credits","100 projects","1,500 tracked keywords","Full feature set included","3 training sessions"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GeoRanker, founded in 2011 and now headquartered in Luxembourg after originating in Bucharest, Romania, is a local SEO and SERP data platform built around a large-scale search results API covering Google, Bing, Baidu, YouTube, Yahoo, and Naver across more than 50,000 geographic locations.$q$, $q$Reported as a lean, roughly eleven-person, largely bootstrapped company generating an estimated $1.2 million in annual revenue with over 20,000 customers, GeoRanker serves both direct SEO practitioners and other software companies that need raw local search data via API.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform combines local citation finding, precise geographic rank tracking, keyword research and density analysis, competitive intelligence, voice search data extraction, and Google Ads competitive auditing.$q$, $q$A large-scale SERP API underpins the entire product, allowing agencies and SaaS companies to pull raw, location-specific ranking data at scale for their own tools and reports.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$GeoRanker uses a monthly credit system rather than flat feature pricing, with credit usage determined by keywords tracked, locations monitored, device type, and number of search engines queried; credits do not roll over between billing periods.$q$, $q$Three published tiers are available: PRO at $99/month (10,000 credits, 50 projects, 100 keywords), AGENCIES at $249/month (50,000 credits, 100 projects, 500 keywords), and ENTERPRISES at $490/month (120,000 credits, 100 projects, 1,500 keywords), all offered pay-as-you-go with no contracts.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f976254-fda1-4e80-a22f-8c5674b5c9b6', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Browser-based Web UI$q$, $q$Provides a tree view of both the media database and the underlying file system for adding, removing, editing, and browsing media.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Automatic metadata extraction$q$, $q$Extracts metadata from MP3, OGG, AAC, M4A, FLAC, WavPack, JPG, and many other audio and image formats.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Thumbnail generation$q$, $q$Automatically generates thumbnails for supported media types for easier browsing on client devices.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Flexible transcoding$q$, $q$Converts media formats on the fly using configurable plugins or external scripts for devices that cannot play the original format natively.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Automatic directory rescans$q$, $q$Detects newly added media in watched directories without requiring manual database refreshes.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Last.fm scrobbling$q$, $q$Tracks and reports listening history to Last.fm directly from the media server.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$External URL support$q$, $q$Includes internet radio streams and other external URLs as browsable media items alongside local files.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Broad platform and architecture support$q$, $q$Runs on Linux, BSD, and macOS across x86, ARM, and MIPS architectures, including low-power devices like Raspberry Pi and NAS units.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Completely free and open source under GPLv2$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Lightweight footprint suitable for low-power hardware like Raspberry Pi and NAS devices$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Broad format support with automatic metadata extraction and thumbnail generation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Flexible, scriptable transcoding for compatibility with a wide range of UPnP devices$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Actively maintained with regular releases since its 2016 fork from MediaTomb$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Not a certified DLNA server, only partial DLNA compatibility, which can cause issues with some devices$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Requires self-hosting and configuration knowledge, unlike consumer-friendly platforms like Plex$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$No built-in user accounts, remote access, or mobile apps found in fuller platforms like Jellyfin or Plex$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Web UI is more utilitarian than the polished client apps offered by commercial alternatives$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$No official support channel beyond community GitHub issues and documentation$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Is Gerbera free?$q$, $q$Yes, Gerbera is free and open source, released under the GPLv2 license.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Is Gerbera the same as MediaTomb?$q$, $q$No, but it is directly descended from it. Gerbera began in 2016 as a fork of MediaTomb after that project's development stalled.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Does Gerbera support DLNA?$q$, $q$Gerbera is a UPnP media server with partial DLNA compatibility; it works with many DLNA devices but is not a certified DLNA server.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$What platforms does Gerbera run on?$q$, $q$Gerbera runs on Linux, BSD, and macOS across x86, ARM, and MIPS architectures, including low-power devices like Raspberry Pi.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Can Gerbera transcode media for incompatible devices?$q$, $q$Yes, Gerbera supports flexible transcoding through configurable plugins or external scripts.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$What media formats does Gerbera support?$q$, $q$Gerbera extracts metadata from and streams formats including MP3, OGG, AAC, M4A, FLAC, WavPack, JPG, and more.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Home network media streaming$q$, $q$Stream a personal music, video, or photo library to smart TVs, media players, and other UPnP-compliant devices on a home network.$q$, $q$Home theater and self-hosting enthusiasts$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Low-power NAS or Raspberry Pi media server$q$, $q$Deploy a lightweight media server on low-power hardware like a NAS unit or Raspberry Pi without the overhead of a full media platform.$q$, $q$Home lab and NAS users$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Legacy device compatibility$q$, $q$Serve media to older smart TVs, UPnP audio receivers, or game consoles that require standard UPnP/DLNA protocol support.$q$, $q$Users with older UPnP/DLNA hardware$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$Free / Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted UPnP media server","Automatic metadata extraction and thumbnails","Flexible plugin/script-based transcoding","Web UI for media and file system browsing","Cross-platform support (Linux, BSD, macOS)"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gerbera is a free, open-source UPnP media server that began in 2016 as a continuation of the stalled MediaTomb project. Released under the GPLv2 license, it streams music, video, and photos across a home network to UPnP-compliant devices such as smart TVs and media players.$q$, $q$The project is actively maintained on GitHub with 1,400 stars, 223 forks, and 41 releases, the latest being version 3.2.1, reflecting a steady, community-driven development cadence since its fork from MediaTomb.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Gerbera offers a browser-based Web UI for browsing the media database and file system, automatic metadata extraction from formats like MP3, OGG, FLAC, AAC, and JPG, thumbnail generation, and flexible plugin- or script-based transcoding for incompatible devices.$q$, $q$Additional capabilities include automatic directory rescanning, Last.fm scrobbling, and support for external URLs such as internet radio streams alongside local media.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Gerbera is completely free and open source under the GPLv2 license, with no paid tiers or licensing fees.$q$, $q$Users self-host Gerbera on their own hardware, from Raspberry Pi devices and NAS units to full desktop or server installations on Linux, BSD, or macOS.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('1fd3a23c-84e4-4c6b-bd89-e880123d495c', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Voice and text interaction$q$, $q$Supports both spoken conversation via integrated text-to-speech/speech-to-text and conventional text-based chat interaction.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Offline-capable, privacy-focused design$q$, $q$Can be configured to run entirely offline, removing dependence on third-party cloud services for core functionality.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Multiple execution modes$q$, $q$Offers 'smart,' 'controlled,' and 'agent' modes for automatic strategy selection, deterministic skills, or multi-step agentic planning.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Layered memory system$q$, $q$Tracks user preferences, ongoing daily context, and historical discussion separately for more persistent, personalized behavior.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Extensible skills architecture$q$, $q$Supports native skills (built-in, fast) and agent skills (flexible, tool-based) that developers can create and share.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Local and remote AI provider support$q$, $q$Can integrate with local, on-device AI models or remote cloud-hosted providers depending on the user's privacy and capability needs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Cross-platform self-hosting$q$, $q$Runs on Linux, macOS, and Windows via CLI setup, Docker, or manual installation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Polyglot bridge architecture$q$, $q$Node.js and Python bridge layers with toolkit definitions allow skills to be built in the language best suited to the task.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Completely free and open source under the MIT License$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Can run fully offline for strong privacy and no dependency on third-party cloud services$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Long project history since 2017 with a large, active GitHub community (~17,400 stars)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Backed by notable sponsors including OpenAI, JetBrains, and MacStadium$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Flexible agentic execution model for multi-step task planning, not just single-turn commands$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Requires self-hosting and a nontrivial technical setup (Node.js, Python, Pipenv dependencies)$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Currently mid-transition to a '2.0 Developer Preview' architecture, meaning ongoing breaking changes$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$No official commercial support; relies on community documentation and GitHub issues$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Voice recognition and TTS quality depend on which providers are configured, offline options may be less accurate than top commercial cloud services$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Not a plug-and-play consumer product like Alexa or Google Assistant$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Is Leon (getleon.ai) free?$q$, $q$Yes, Leon is completely free and open source under the MIT License.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Who created Leon?$q$, $q$Leon was created by developer Louis Grenard, with the project dating back to 2017 and active development since 2019.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Can Leon run fully offline?$q$, $q$Yes, Leon can be configured to operate entirely offline, without relying on third-party cloud services, for maximum privacy.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$What platforms does Leon support?$q$, $q$Leon runs on Linux, macOS, and Windows, and can be installed via a CLI setup wizard, Docker, or manual installation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Does Leon support voice interaction?$q$, $q$Yes, Leon supports both voice (via text-to-speech and speech-to-text) and text-based chat interaction.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Is Leon still in active development?$q$, $q$Yes, Leon is undergoing a major architectural transition and is currently in a '2.0 Developer Preview' phase with ongoing active development.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Privacy-focused personal assistant$q$, $q$Users who don't want their voice assistant data sent to third-party clouds self-host Leon to run assistant functionality entirely offline.$q$, $q$Privacy-conscious individuals and self-hosters$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Custom skill development$q$, $q$Developers build and share custom native or agent skills to extend Leon's capabilities for specific personal or home automation tasks.$q$, $q$Developers and open-source contributors$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Multi-step agentic task automation$q$, $q$Users leverage Leon's 'agent' execution mode to plan and carry out multi-step tasks rather than issuing single, isolated commands.$q$, $q$Power users and AI hobbyists$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$Free / Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted personal AI assistant","Voice and text interaction","Offline-capable operation","Smart, controlled, and agent execution modes","Extensible native and agent skills architecture","Cross-platform support (Linux, macOS, Windows)"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Leon (getleon.ai) is a free, open-source, self-hosted personal AI assistant created by developer Louis Grenard, with roots dating to 2017 and active development since 2019. Released under the MIT License, it supports both voice and text interaction and can run fully offline for maximum privacy.$q$, $q$The project has grown to roughly 17,400 GitHub stars and 1,500 forks, with sponsorship from OpenAI, JetBrains, and MacStadium, and is currently undergoing a major architectural evolution toward agentic, tool-based execution in its '2.0 Developer Preview' phase.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Leon supports three execution modes: 'smart' (automatic strategy selection), 'controlled' (deterministic native skills), and 'agent' (step-by-step planning for multi-step tasks), backed by a layered memory system for preferences, daily context, and discussion history.$q$, $q$Its extensible skills architecture splits into native skills (fast, built-in) and agent skills (flexible, tool-based), with Node.js and Python bridge layers letting developers build and share custom capabilities.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c6b68bfb-e7f4-4aa7-b7c2-1fa1787822c7', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Leon is completely free and open source under the MIT License, with no paid tiers or subscription fees for the software itself.$q$, $q$Users self-host Leon on their own server (Linux, macOS, or Windows), so the only costs involved are the user's own infrastructure and, optionally, any third-party cloud AI provider fees if configured to use remote models.$q$]::text[], 2);
