-- Enrichment marathon batch: Genea.app, Genealogy, General Translation, Geneva, GeneWeb, GeoRanker, Gerbera, getleon

-- ── Genea.app ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Genea.app is a free, open-source, serverless browser tool for building and editing GEDCOM-compatible family trees, with optional Git-based syncing across devices.$q$, short_description),
  pricing_model = COALESCE($q$Free / Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Genea.app Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Genea.app is a free, open-source, browser-based family tree builder with GEDCOM support and Git syncing. See features, pricing and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Genea.app is a free, open-source, browser-based tool for building, editing, and visualizing family trees using the GEDCOM genealogy data standard. The project is maintained under the genea-app organization on GitHub, with its source code released under the MIT License and a copyright date of 2021, which places the project's origin around that year. Unlike most consumer genealogy products, Genea.app does not require an account, a subscription, or a backend server of any kind. It is described by its creators as a 'completely serverless solution for consuming and authoring GEDCOM genealogy data,' meaning every part of the experience, from parsing an imported file to rendering the interactive tree, happens entirely inside the user's web browser. Because there is no server processing personal data, Genea.app markets itself explicitly around 'privacy by design': family history data, which can include sensitive information about living relatives, never leaves the user's device unless the user chooses to export or sync it themselves. This positions the tool as an alternative to hosted genealogy platforms such as Ancestry, MyHeritage, or FamilySearch, which store family tree data on their own servers and often gate advanced features behind paid membership tiers. Genea.app's core workflow starts either from a blank tree or from an imported GEDCOM file, the open, decades-old interchange format supported by virtually every genealogy application, including the major commercial services. Because Genea.app both reads and writes standard GEDCOM, a user can bring in a tree exported from MyHeritage, FamilySearch, or Ancestry, edit and extend it locally, and then export it again or move it to a different tool entirely, avoiding vendor lock-in. To help new users understand the interface before committing their own family data, the site also ships with a handful of sample trees, including a Royal lineage, a set of past United States presidents, and a fictional Harry Potter family tree, that visitors can explore immediately without importing anything. Since Genea.app keeps no server-side copy of a user's tree, the project had to solve the multi-device synchronization problem differently than a typical SaaS app. Its answer is twofold. First, users can simply save their GEDCOM file locally and move it between devices manually, for example by emailing it to themselves or storing it in a general-purpose cloud drive such as Dropbox. Second, and more distinctively, Genea.app includes a built-in Git integration, letting users connect the app to a private or public Git repository, whether hosted on GitHub, GitLab, or a self-hosted Git server such as Gitea, Gogs, or GitBucket, and use ordinary version-controlled commits to store and sync tree changes. This Git-based approach gives technically inclined users full version history of their genealogical research, the ability to branch and experiment with alternative theories about ancestry, and complete control over where their data physically lives, all without Genea.app itself hosting or ever seeing that data. The tool works on both desktop and mobile browsers, so a user can review or lightly edit a tree from a phone as easily as from a laptop, though heavier editing sessions are more practical on larger screens given the visual, node-based nature of family tree interfaces. Because Genea.app is a small, community-maintained open-source project rather than a funded company, it does not publish information about company size, headquarters, revenue, or a named founder; contributions and issue discussion happen publicly through the genea-app GitHub organization, and the project's roadmap and support channel are the GitHub issue tracker itself. This also means Genea.app has no formal customer support team, no enterprise sales process, and no roadmap commitments beyond what volunteer maintainers choose to build. Its closest competitors fall into two very different categories: large hosted genealogy platforms like Ancestry, MyHeritage, FamilySearch, and Geni, which offer research databases, DNA matching, and record hints but require accounts and often subscriptions; and other open-source or self-hosted family tree tools such as Gramps (a mature, feature-rich desktop application) and GeneWeb (a server-based genealogy engine, also covered separately in this directory), which target more advanced genealogists willing to install and run software rather than use a purely in-browser tool. Genea.app's differentiation is its combination of zero installation, zero account requirement, and zero server dependency, which makes it attractive to privacy-conscious hobbyists, developers who want to inspect or extend an open codebase, and anyone who wants a lightweight way to view or lightly edit a GEDCOM file without committing to a larger genealogy ecosystem. The tradeoff is that it lacks the record-hint databases, DNA integration, and collaborative research communities that make paid platforms valuable for serious ancestry research; Genea.app is best understood as a focused, no-frills tree editor and viewer rather than a full genealogy research service.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'cd31d369-2e60-4849-9a2b-8481c41a9d08';

